    return buffer;
}

int parse_int(const char *str, int *result) {
    if (!str || !result) return -1;
    while (*str == ' ') str++;
    int sign = 1;
    if (*str == '-' || *str == '+') {
        sign = (*str == '-') ? -1 : 1;
        str++;
    }
    if (*str < '0' || *str > '9') return -1;
    long long val = 0;
    while (*str >= '0' && *str <= '9') {
        val = val * 10 + (*str - '0');
        if (sign == 1 && val > (long long) INT_MAX) {
            *result = INT_MAX;
            return -1;
        }
        if (sign == -1 && -val < (long long) INT_MIN) {
            *result = INT_MIN;
            return -1;
        }
        str++;
    }
    if (*str != '\0') return -1;
    *result = (int)(sign * val);
    return 0;
}

int parse_int(const char *str, int *out) {
    if (!str || !out) return -1;
    while (*str == ' ') str++;
    int sign = 1;
    if (*str == '-' || *str == '+') {
        if (*str == '-') sign = -1;
        str++;
    }
    if (*str < '0' || *str > '9') return -1;
    unsigned long long val = 0;
    while (*str >= '0' && *str <= '9') {
        int digit = *str - '0';
        if (val > (ULLONG_MAX - digit) / 10) return -1;
        val = val * 10 + digit;
        str++;
    }
    while (*str == ' ') str++;
    if (*str != '\0') return -1;
    if (sign == 1) {
        if (val > INT_MAX) return -1;
        *out = (int)val;
    } else {
        if (val > (unsigned long long)INT_MAX + 1) return -1;
        *out = (int)(-(long long)val);
    }
    return 0;
}

#include <ctype.h>
#include <limits.h>

int parse_int(const char *str, int *value) {
    if (!str || !value) return -1;

    // Skip leading whitespace
    while (isspace((unsigned char)*str)) str++;

    // Determine sign
    int sign = 1;
    if (*str == '-') {
        sign = -1;
        str++;
    } else if (*str == '+') {
        str++;
    }

    // Must have at least one digit
    if (!isdigit((unsigned char)*str)) return -1;

    long long acc = 0;
    while (isdigit((unsigned char)*str)) {
        int digit = *str - '0';
        acc = acc * 10 + digit;

        // Check for overflow
        if (sign == 1 && acc > INT_MAX) return -1;
        if (sign == -1 && acc > -(long long)INT_MIN) return -1;

        str++;
    }

    *value = (int)(sign * acc);
    return 0;
}

