int parse_int(const char *s, int *result) {
    if (!s || !result) return -1;
    while (isspace((unsigned char)*s)) s++;
    int sign = 1;
    if (*s == '-') { sign = -1; s++; }
    else if (*s == '+') { s++; }
    if (!isdigit((unsigned char)*s)) return -1;
    long long val = 0;
    while (isdigit((unsigned char)*s)) {
        int digit = *s - '0';
        if (val > (LLONG_MAX - digit) / 10) return -1;
        val = val * 10 + digit;
        s++;
    }
    if (sign == 1 && val > INT_MAX) return -1;
    if (sign == -1 && val > (long long)INT_MAX + 1) return -1;
    *result = (int)(sign * val);
    return 0;
}

#include <limits.h>
#include <ctype.h>

int parse_int(const char *str, int *value) {
    if (!str || !value) return -1;

    /* skip leading whitespace */
    while (isspace((unsigned char)*str))
        str++;
    if (*str == '\0') return -1;   /* no digits */

    int sign = 1;
    if (*str == '-' || *str == '+') {
        if (*str == '-') sign = -1;
        str++;
    }

    if (!isdigit((unsigned char)*str))
        return -1;                 /* at least one digit required */

    long long mag = 0;
    while (*str && isdigit((unsigned char)*str)) {
        int digit = *str - '0';

        /* prevent long‑long overflow before it happens */
        if (mag > (LLONG_MAX - digit) / 10)
            return -1;             /* number too large for any integer type */

        mag = mag * 10 + digit;

        /* early overflow check for int range */
        if (sign > 0 && mag > INT_MAX)
            return -1;
        if (sign < 0 && mag > (long long)INT_MAX + 1)
            return -1;

        str++;
    }

    /* final range check */
    if (sign > 0) {
        if (mag > INT_MAX) return -1;
        *value = (int)mag;
    } else {
        if (mag > (long long)INT_MAX + 1) return -1;
        *value = (int)-mag;
    }
    return 0;
}

