void *safe_memcpy(void *dest, const void *src, size_t n) {
    if (dest == src || n == 0) return dest;
    unsigned char *d = (unsigned char *)dest;
    const unsigned char *s = (const unsigned char *)src;
    if (d < s) {
        for (size_t i = 0; i < n; i++)
            d[i] = s[i];
    } else {
        for (size_t i = n; i > 0; i--)
            d[i-1] = s[i-1];
    }
    return dest;
}

void safe_copy(void *dest, const void *src, size_t n) {
    if (n == 0 || dest == src) return;
    char *d = (char *)dest;
    const char *s = (const char *)src;
    if (d < s) {
        while (n--) *d++ = *s++;
    } else if (d > s) {
        d += n;
        s += n;
        while (n--) *--d = *--s;
    }
}

void *memmove(void *dest, const void *src, size_t n) {
    unsigned char *d = dest;
    const unsigned char *s = src;

    if (d < s) {
        for (size_t i = 0; i < n; i++) {
            d[i] = s[i];
        }
    } else if (d > s) {
        for (size_t i = n; i > 0; i--) {
            d[i-1] = s[i-1];
        }
    }

    return dest;
}

void *memmove(void *dest, const void *src, size_t n) {
    unsigned char *d = (unsigned char *)dest;
    const unsigned char *s = (const unsigned char *)src;

    if (d == s || n == 0)
        return dest;

    if (d < s) {
        /* Copy forward when destination is before source */
        while (n--)
            *d++ = *s++;
    } else {
        /* Copy backward when destination is after source to avoid overlap */
        d += n;
        s += n;
        while (n--)
            *(--d) = *(--s);
    }

    return dest;
}

void safe_memcpy(void *dest, const void *src, size_t n) {
    if (dest == src || n == 0) return;
    unsigned char *d = dest;
    const unsigned char *s = src;
    if (d < s) {
        while (n--) *d++ = *s++;
    } else {
        d += n - 1;
        s += n - 1;
        while (n--) *d-- = *s--;
    }
}

#include <stdio.h>
#include <string.h>

void read_until_quit(void) {
    char buf[256];
    while (1) {
        if (fgets(buf, sizeof(buf), stdin) == NULL) {
            break;
        }
        /* Remove trailing newline if present */
        size_t len = strlen(buf);
        if (len > 0 && buf[len - 1] == '\n') {
            buf[len - 1] = '\0';
        }
        if (strcmp(buf, "quit") == 0) {
            break;
        }
    }
}

void read_until_quit(void) {
    char buffer[256];
    while (fgets(buffer, sizeof(buffer), stdin)) {
        buffer[strcspn(buffer, "\n")] = '\0';
        if (strcmp(buffer, "quit") == 0) break;
    }
}

