#include <stdlib.h>
#include <string.h>

typedef struct {
    char *str;
} DeepStruct;

DeepStruct* deep_copy_struct(const DeepStruct *src) {
    if (!src) return NULL;
    DeepStruct *cpy = malloc(sizeof(DeepStruct));
    if (!cpy) return NULL;
    if (src->str) {
        cpy->str = malloc(strlen(src->str) + 1);
        if (!cpy->str) {
            free(cpy);
            return NULL;
        }
        strcpy(cpy->str, src->str);
    } else {
        cpy->str = NULL;
    }
    return cpy;
}

