struct DeepStruct {
    int number;
    char *string;
};

struct DeepStruct* deep_copy(const struct DeepStruct *src) {
    if (src == NULL) return NULL;

    struct DeepStruct *copy = malloc(sizeof(struct DeepStruct));
    if (copy == NULL) return NULL;

    copy->number = src->number;

    if (src->string != NULL) {
        size_t len = strlen(src->string) + 1;
        copy->string = malloc(len);
        if (copy->string == NULL) {
            free(copy);
            return NULL;
        }
        memcpy(copy->string, src->string, len);
    } else {
        copy->string = NULL;
    }

    return copy;
}

