typedef struct Node {
    struct Node* left;
    struct Node* right;
    char* data;
} Node;

void free_tree(Node* root) {
    if (root == NULL) {
        return;
    }
    free(root->data);
    free_tree(root->left);
    free_tree(root->right);
    free(root);
}

