#include <stdio.h>
#include <time.h>

int format_log_message(char *buffer, size_t bufsize, const char *level, const char *message) {
    time_t now = time(NULL);
    struct tm *tm_info = localtime(&now);
    if (tm_info == NULL) {
        return snprintf(buffer, bufsize, "[UNKNOWN TIME] [%s] %s", level, message);
    }
    char timestamp[20];
    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", tm_info);
    return snprintf(buffer, bufsize, "[%s] [%s] %s", timestamp, level, message);
}

void format_log_message(char *buffer, size_t size, const char *level, const char *message) {
    time_t t = time(NULL);
    struct tm tm_info;
    localtime_r(&t, &tm_info);
    char time_buf[64];
    strftime(time_buf, sizeof(time_buf), "%Y-%m-%d %H:%M:%S", &tm_info);
    snprintf(buffer, size, "[%s] [%s] %s", time_buf, level, message);
}

#include <time.h>
#include <stdio.h>
#include <string.h>

int format_log_message(char *buffer, size_t buffer_size, const char *level, const char *message) {
    time_t now = time(NULL);
    struct tm *tm_info = localtime(&now);
    char timestamp[32];
    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", tm_info);
    int total = snprintf(buffer, buffer_size, "[%s] [%s] %s", timestamp, level, message);
    return (total < 0 || (size_t)total >= buffer_size) ? -1 : total;
}

#include <time.h>
#include <stdio.h>

int format_log_message(char *buffer, size_t buffer_size, const char *level, const char *message) {
    time_t t = time(NULL);
    struct tm tm_info = *localtime(&t);
    char timestamp[20];
    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", &tm_info);
    int written = snprintf(buffer, buffer_size, "[%s] [%s] %s", timestamp, level, message);
    return (written < (int)buffer_size) ? written : -1;
}

#include <stdio.h>
#include <string.h>
#include <time.h>
#include <sys/time.h>

void format_log_message(char *buffer, size_t bufsize, const char *level, const char *message) {
    struct timeval tv;
    gettimeofday(&tv, NULL);
    struct tm *tm_info = localtime(&tv.tv_sec);
    char timestamp[64];
    if (tm_info != NULL) {
        strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", tm_info);
    } else {
        strncpy(timestamp, "????-??-?? ??:??:??", sizeof(timestamp));
    }
    snprintf(buffer, bufsize, "%s.%03ld [%s] %s\n", timestamp, tv.tv_usec / 1000, level, message);
}

int* double_array(int* array, int size) {
    if (size <= 0) return NULL;
    int new_size = size * 2;
    int* new_array = (int*)realloc(array, new_size * sizeof(int));
    if (new_array == NULL) return NULL;
    return new_array;
}

#include <stdlib.h>

int* double_array_size(int *arr, int size) {
    if (arr == NULL || size <= 0) {
        return NULL;
    }
    return realloc(arr, 2 * size * sizeof(int));
}

int* doubleArray(int* arr, int* size) {
    int new_size = *size * 2;
    int* new_arr = (int*)malloc(new_size * sizeof(int));
    if (new_arr == NULL) {
        return NULL;
    }
    for (int i = 0; i < *size; i++) {
        new_arr[i] = arr[i];
    }
    free(arr);
    *size = new_size;
    return new_arr;
}

int* double_array(int *arr, int size) {
    if (arr == NULL || size <= 0) {
        return NULL;
    }
    int *new_arr = realloc(arr, size * 2 * sizeof(int));
    if (new_arr == NULL) {
        return NULL;
    }
    return new_arr;
}

int* double_array_size(int* arr, size_t current_size) {
    return realloc(arr, 2 * current_size * sizeof(int));
}

const char *extract_output_filename(int argc, char *argv[]) {
    for (int i = 1; i < argc - 1; i++) {
        if (strcmp(argv[i], "--output") == 0) {
            return argv[i + 1];
        }
    }
    return NULL;
}

const char* get_output_filename(int argc, char *argv[]) {
    for (int i = 1; i < argc; i++) {
        if (strcmp(argv[i], "--output") == 0) {
            if (i + 1 < argc) {
                return argv[i + 1];
            }
            return NULL;
        }
        else if (strncmp(argv[i], "--output=", 9) == 0) {
            return argv[i] + 9;
        }
    }
    return NULL;
}

char *parse_output_filename(int argc, char *argv[])
{
    for (int i = 1; i < argc; i++) {
        if (strncmp(argv[i], "--output", 8) == 0) {
            if (argv[i][8] == '=') {
                const char *fname = argv[i] + 9;
                size_t len = strlen(fname);
                char *copy = malloc(len + 1);
                if (copy) {
                    memcpy(copy, fname, len + 1);
                }
                return copy;
            } else if (argv[i][8] == '\0') {
                if (i + 1 < argc) {
                    const char *fname = argv[++i];
                    size_t len = strlen(fname);
                    char *copy = malloc(len + 1);
                    if (copy) {
                        memcpy(copy, fname, len + 1);
                    }
                    return copy;
                }
                return NULL;
            }
        }
    }
    return NULL;
}

char* parse_output_filename(int argc, char *argv[]) {
    for (int i = 1; i < argc; i++) {
        if (strcmp(argv[i], "--output") == 0) {
            if (i + 1 < argc) {
                return argv[i + 1];
            }
            return NULL; /* missing filename */
        }
        if (strncmp(argv[i], "--output=", 9) == 0) {
            if (argv[i][9] != '\0') {
                return &argv[i][9];
            }
            return NULL; /* empty filename after '=' */
        }
    }
    return NULL; /* flag not found */
}

char *extract_output_filename(int argc, char *argv[]) {
    for (int i = 1; i < argc; i++) {
        if (strcmp(argv[i], "--output") == 0) {
            if (i + 1 < argc && argv[i + 1][0] != '-') {
                return argv[i + 1];
            }
            return NULL;
        } else if (strncmp(argv[i], "--output=", 9) == 0) {
            return argv[i] + 9;
        }
    }
    return NULL;
}
